head.script:
//var loginDTO =  LoginUtil.getLoginDTO(request); // 세션정보
scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6) , 0).getDate();  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)
//scwin.strPreDate = WebSquare.date.dateAdd(scwin.vCurDate, -2);
scwin.strPreDate = $c.date.addMonth(scwin.vCurDate, -1);

scwin.loUpperLobranCd = ""; // 물류상위점소코드
scwin.userClsCd = ""; // 사용자구분코드
scwin.clntNo = ""; // 거래처번호
scwin.clntNm = ""; // 거래처명
scwin.cvsslMgntNo = "";

scwin.onpageload = function() {
    let memJson = $c.data.getMemInfo();
    console.log(memJson);

    scwin.loUpperLobranCd = memJson.loUpperLobranCd; // 물류상위점소코드
    scwin.userClsCd = memJson.userClsCd; // 사용자구분코드
    scwin.clntNo = memJson.clntNo; // 거래처번호
    scwin.clntNm = memJson.clntNm; // 거래처명

    let args = $c.data.getParameter();

    if(args.arrParam0 != "" && args.arrParam0 != null){
        scwin.cvsslMgntNo = args.arrParam0.trim();    
    }
    console.log("scwin.cvsslMgntNo : ", scwin.cvsslMgntNo);

    ed_cvsslMgntNo.setValue(scwin.cvsslMgntNo);
    ds_lobran.removeAll();
    $c.sbm.execute(sbm_lobran);
};

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

        if (scwin.userClsCd != '01') { // 사용자구분이 내부사용자가 아니면
            ed_con_shpCo.setValue(scwin.clntNo); //거래처번호
            ed_con_shpCoNm.setValue(scwin.clntNm); // 거래처명
            $c.gus.cfDisableObjects([ed_con_shpCo,ed_con_shpCoNm]); //cfDisableObjects([ed_con_shpCo,txt_con_shpCoNm]);
        } else {
            $c.gus.cfEnableObjects([ed_con_shpCo,ed_con_shpCoNm]); //cfEnableObjects([ed_con_shpCo,txt_con_shpCoNm]);
        }

        scwin.f_setDate();
        scwin.f_Retrieve();
    }, {"delay":50});
};


scwin.f_Retrieve = async function () {
    var rtn = await $c.gus.cfValidate([ed_qryStDt,ed_qryEndDt]); // 필수조건 : 조회기간
    if (!rtn) {	
  		return;
	}

    if (ed_qryStDt.getValue() > ed_qryEndDt.getValue()) {
		$c.win.alert(MSG_CM_ERR_039);
		ed_qryEndDt.focus();
		return;
	}

    const params = {
        lobranCd    : lc_lobran.getValue() , 
        shpCoClntNo : ed_con_shpCo.getValue(),
        vsslCd      : ed_vsslCd.getValue(),
        qryStDt     : ed_qryStDt.getValue(),
        qyrEndDt    : ed_qryEndDt.getValue(),
        cvsslMgntNo : ed_cvsslMgntNo.getValue(),
        mrn         : ed_mrn.getValue()
    };

////////////////임시 세팅 start ///////////////////
/*
    params.lobranCd = '2AA';
    params.qryStDt = '20220101'
    params.qyrEndDt = '20251001'
*/
////////////////임시 세팅 end ///////////////////

    //데이터셋에 정보설정
    dma_search.setJSON(params);
    $c.sbm.execute(sbm_retrieve);
}

scwin.f_setDate = function () {
    var dateStr = scwin.vCurDate.substring(0, 6);

	if (scwin.cvsslMgntNo != "" && scwin.cvsslMgntNo.length > 4) {
    	dateStr = dateStr.substring(0,2) + scwin.cvsslMgntNo.substring(1,5);
    }

	var firstDate = dateStr+"01";
	var startDt   = firstDate.toDate("YYYYMMDD");
	var endDt     = startDt.after(0, 1, 0);
		endDt     = endDt.before(0, 0, 1);

	ed_qryStDt.setValue(startDt.format("YYYYMMDD"));
	ed_qryEndDt.setValue(endDt.format("YYYYMMDD"));
}


scwin.f_chkOpenCommonPopUpEmEdit = function(gubun, chkObj, txtObj, disGubun, pAllSearch) {
	var pCode = "";
	var pName = "";

    if (disGubun == 2) { // 선석팝업을 띠우면
    	if (scwin.userClsCd != '01') return; // 사용자구분이 내부사용자가 아니면
    }

	if(gubun == 1) {
		txtObj.setValue("");
		if (chkObj.getValue == "") {
            return;
        }
	} else if (gubun == 2) {
		chkObj.setValue("");
		if (txtObj.getValue() == "") {
            return;
        }
	}

	pCode = chkObj.getValue().replace(/^\s*/,'');
	pName = txtObj.getValue();

	scwin.f_openCommonPopUp(disGubun, pCode, pName, 'T', pAllSearch);
}


scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;  // 공통POP-UP -> 요청화면

	switch (disGubun) {
		case 1: // 선박 팝업
			rtnList = udc_comCodeVssl.cfCommonPopUp(scwin.callbackVsslCdInfo, pCode, pName, "T", null, null, null, null, null,null,null,null,null,null,pAllSearch);

			//cfSetReturnValue(rtnList, ed_vsslCd, txt_vsslNm);
            //$c.gus.cfSetReturnValue(rtnList, ed_vsslCd, ed_vsslNm);
			break;

		case 2: // 선사 팝업

			rtnList = udc_comCodeShp.cfCommonPopUp(scwin.callbackClntInfo	    // XML상의 SELECT ID	
                                    ,pCode					// 화면에서의 ??? Code Element의	Value
                                    ,pName					// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                    ,'SHP'					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					// 윈도우 위치 Y좌표	
                                    ,null					// 윈도우 위치 X좌표
                                    ,null					// 중복체크여부	("F")
                                    ,pAllSearch					// 전체검색허용여부	("F")
                                    ,"선사,선사코드,선사명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    );

			//$c.gus.cfSetReturnValue(rtnList, ed_con_shpCo, ed_con_shpCoNm);
			break;	
	}
}

scwin.callbackVsslCdInfo = function (rtnList) {
    if(rtnList != null && rtnList != "N/A"){
        $c.gus.cfSetReturnValue(rtnList, ed_vsslCd, ed_vsslNm);
    } else {
        ed_vsslCd.setValue("");
        ed_vsslNm.setValue("");
    }
}


scwin.callbackClntInfo = function (rtnList) {
    if(rtnList != null && rtnList != "N/A"){
        $c.gus.cfSetReturnValue(rtnList, ed_con_shpCo, ed_con_shpCoNm);
    } else {
        ed_con_shpCo.setValue("");
        ed_con_shpCoNm.setValue("");
    }
}

scwin.f_FieldClear = function () {

	if (scwin.userClsCd != '01') { // 사용자구분이 내부사용자가 아니면
    	$c.gus.cfInitObjects([lc_lobran,ed_vsslCd,ed_vsslNm]);
    } else {
    	$c.gus.cfInitObjects([lc_lobran,ed_vsslCd,ed_vsslNm,ed_con_shpCo,ed_con_shpCoNm,ed_cvsslMgntNo]);
    }
    if (scwin.cvsslMgntNo == "") {
    	lc_lobran.setValue(scwin.loUpperLobranCd);
    } else {
    	//lc_lobran.index = 0;
    }
    scwin.f_setDate();
	lc_lobran.focus();
}



scwin.sbm_lobran_submitdone = function (e) {
    var rowCnt = ds_lobran.getRowCount();
    if (rowCnt == 0) return;

	//ds_lobran.insertRow(0);
	//ds_lobran.NameValue(1,"lobranCd") = "";
    //ds_lobran.setCellData(0, "lobranCd", "");
	//ds_lobran.NameValue(1,"lobranNm") = "전체";
    //ds_lobran.setCellData(0, "lobranNm", "전체");

  	if (scwin.cvsslMgntNo == "") {
    	lc_lobran.setValue(scwin.loUpperLobranCd);
    } else {
    	//lc_lobran.index = 0;
    }
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};


scwin.gr_vesselMng_oncelldblclick = function (rowIndex, columnIndex, columnId) {

	var rtnValues = new Array();

    rtnValues[0]  = ds_vesselMng.getCellData(rowIndex,"cvsslMgntNo"); //본선관리번호
    rtnValues[1]  = ds_vesselMng.getCellData(rowIndex,"lobranCd"); //선박코드
    rtnValues[2]  = ds_vesselMng.getCellData(rowIndex,"lobranNm"); //선박명
    rtnValues[3]  = ds_vesselMng.getCellData(rowIndex,"vsslCd"); //마감일자
    rtnValues[4]  = ds_vesselMng.getCellData(rowIndex,"vsslNm"); //마감시간
    rtnValues[5]  = ds_vesselMng.getCellData(rowIndex,"mrn"); //도착(입항)일자
    rtnValues[6]  = ds_vesselMng.getCellData(rowIndex,"vsslPurpsNm"); //도착(입항)시간
    rtnValues[7]  = ds_vesselMng.getCellData(rowIndex,"portCd"); //출발(출항)일자
    rtnValues[8]  = ds_vesselMng.getCellData(rowIndex,"pierCd"); //출발(출항)시간
    rtnValues[9]  = ds_vesselMng.getCellData(rowIndex,"pierNm"); //출발(출항)시간		
    rtnValues[10] = ds_vesselMng.getCellData(rowIndex,"arvDtm"); //선사항차
    rtnValues[11] = ds_vesselMng.getCellData(rowIndex,"dptDtm"); //선사항차
    rtnValues[12] = ds_vesselMng.getCellData(rowIndex,"alngpierDtm"); //항구코드
    rtnValues[13] = ds_vesselMng.getCellData(rowIndex,"offpierDtm"); //부두코드
    rtnValues[14] = ds_vesselMng.getCellData(rowIndex,"adptHh"); //부두코드명
    rtnValues[15] = ds_vesselMng.getCellData(rowIndex,"agrWt"); //LINE 코드
    rtnValues[16] = ds_vesselMng.getCellData(rowIndex,"ocshipYn"); //LINE 코드		
    rtnValues[17] = ds_vesselMng.getCellData(rowIndex,"ocshipNm"); //LINE 코드	

	$c.win.closePopup(rtnValues , "");
};

